#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int *A = (int*)malloc(N*sizeof(int));
        int *B = (int*)malloc(N*sizeof(int));
        int hasOne=0, ok=1;
        for(int i=0;i<N;i++) scanf("%d",&A[i]);
        for(int i=0;i<N;i++) scanf("%d",&B[i]);
        if(A[0]!=B[0]||A[N-1]!=B[N-1]) ok=0;
        for(int i=0;i<N;i++) if(A[i]==1) hasOne=1;
        for(int i=1;i<N-1 && ok;i++) if(A[i]==1 && B[i]==0) ok=0;
        if(!hasOne && ok){
            for(int i=0;i<N && ok;i++) if(B[i]==1) ok=0;
        }
        printf(ok?"YES\n":"NO\n");
        free(A); free(B);
    }
    return 0;
}

